static function string Before(string s, string sep) 
{
      if (sep.Length == 0) { 
        return s; 
      }
      bool flag = s.Contains(sep);
      if (flag == false) {
        return s;
      }
      int ind = s.IndexOf(sep);
      return s.Substring(0, ind); 
}

static function string After(string s, string sep) 
{
      if (sep.Length == 0) { 
        return ""; 
      }
      bool flag = s.Contains(sep);
      if (flag == false) {
        return "";
      }
      int ind = s.IndexOf(sep);
      return s.Substring(ind + sep.Length); 
}

static function double Log(double y) 
{ double x = (y-1)/(y+1); 
  double x2 = x*x; 
  double result = x;

  for (int i = 1; i <= 200; i+1) {
    int j = 2*i + 1;
    x = x*x2;
    result = result + x/j;
  }

  return 2*result;
}

static function double Log10(double x) 
{ double ln10 = 2.302585092994046; // Constant value for ln(10)
  double y = Log(x);        
  return y / ln10;
}

static function long Gcd(long xx, long yy) 
{ long x = CommonLib.Math.Abs(xx) as long; 
  long y = CommonLib.Math.Abs(yy) as long; 
  while (x != 0 && y != 0) { 
      long z = y; 
      y = x % y; 
      x = z; 
  } 

  if (y == 0) { 
      return x; 
  } 

  if (x == 0) { 
      return y; 
  } 

  return 0; 
}

static function Collection[int] integerSubrange(int i, int j) 
{ Collection[int] res; 
  for (int x = i; x <= j; x+1) { 
  	res.Add(x); 
  } 
  return res; 
}

static function Collection[string] Characters(string s) 
{
  Collection[string] res; 
  for (int i = 0; i < s.Length; i+1) { 
  	res.Add("" + s.CharAt(i)); 
  } 
  return res; 
}

static function double Sinh(double x) 
{ double y = CommonLib.Math.Pow(2.718281828, x); 
  return 0.5*(y - (1/y)); 
}

static function double Cosh(double x) 
{ double y = CommonLib.Math.Pow(2.718281828, x); 
  return 0.5*(y + (1/y));
}

static function double Tanh(double x) 
{ double y = CommonLib.Math.Pow(2.718281828, x); 
  y = y*y; 
  return (y - 1)/(y + 1);
}

