static function Collection[string] AllMatches(string str, string regex) 
{
   try {
     RegExpLib.VerbalExpressions expressions;
     Array[string] result = expressions.GetMatches(str, regex);
     return result.ToCollection();
   } 
   catch Exception e {
       return null;
   }
}

static function string FirstMatch(string str, string regex) 
{
      try {
        RegExpLib.VerbalExpressions expressions;
        string result = expressions.GetMatch(str, regex);
        return result;
      } 
      catch Exception e {
            return null;
      }
}

static function string StringSubtract(string s1, string s2) 
{ string res = ""; 
  for (int i = 0; i < s1.Length; i+1)
  { string ch = "" + s1.CharAt(i); 
    if (s2.IndexOf(ch) < 0)
    { res = res + ch; } 
  } 
  return res; 
}

static function bool IsInteger(string str) 
{  try { 
     int x = int.Parse(str); 
     return (x + "") == str; 
   }
   catch Exception e {
     return false; 
   }
}

static function bool IsReal(string str) 
{
  try { 
    double d = double.Parse(str); 
    if (d == null) {
       return false;
    }

    if (d + "") == str
    { return true; } 
    return false; 
  }
  catch Exception e {
    return false; 
  }

}

static function bool IsLong(string str) 
{
  try { 
    long l = long.Parse(str); 
    if (l == null) {
      return false;
    }

    if (l + "") == str
    { return true; } 
    return false; 
  }
  catch Exception e {
    return false; 
  }
}

static function bool HasMatch(string str, string regex) 
{
  try {
    RegExpLib.VerbalExpressions expressions;
    string result = expressions.Then(regex).GetMatch(str, "");
    if (result.Length != 0) {
        return true;
    }
    return false;
  } 
  catch Exception e {
        return false;
  }
}

static function double NormalDist(double x, double mu, double sigma) 
{ 
  double disp = (x-mu)/sigma; 
  double twopi = 2 * CommonLib.Math.Pi(); 
  double result = (1.0/(sigma* CommonLib.Math.Sqrt(twopi))) * 
                  CommonLib.Math.Pow(2.718281828, -0.5*disp*disp); 
  return result; 
}

static function double cumulativeNormalDist(double x, double m, double sigma) 
{
  double k = ( 1 / ( 1 + 0.2316419 * ( x - m ) ) ); 
  double poly = ( 0.31938153 * k ) + ( -0.356563782 * k * k ) + 
               ( 1.781477937 * k * k * k ) + ( -1.821255978 * k * k * k * k ) + 
               ( 1.330274429 * k * k * k * k * k ); 
  double result = 1 - NormalDist(x,m,sigma) * poly;
  return result; 
}

static function double Norm_S_Dist(double x, bool cum) 
{ double result; 
  if cum == false 
  { result = NormalDist(x,0,1); } 
  else 
  { result = cdfNormalDist(x,0,1); }
  return result; 
}

static function double cdfNormalDist(double x, double m, double sigma) 
{ double result; 
  if x >= m 
  { result = cumulativeNormalDist(x,m,sigma); } 
  else 
  { result = 1 - cumulativeNormalDist(m + (m-x),m,sigma); }
  return result; 
}

static function double Ln(double y) 
{
  double x = (y-1)/(y+1); 
  double x2 = x*x; 
  double result = x;

  for (int i = 1; i <= 200; i+1) {
    int j = 2*i + 1;
    x = x*x2;
    result = result + x/j;
  }

  return 2*result;
}

static function double D1(double S, double K, double Vol, double R, double Q, double T) 
{
    double result;
    double D1;
    D1 = ((Ln((S / (1.0 * K))) + (((R - Q) + ((Vol * Vol) / ((1.0 * 2) as double))) * T)) / 
               (1.0 * (Vol * CommonLib.Math.Sqrt(T))));
    return D1;
}

static function double D2(double S, double K, double Vol, double R, double Q, double T) 
{
    double result;
    double D2;
    D2 = (D1(S, K, Vol, R, Q, T) - (Vol * CommonLib.Math.Sqrt(T)));
    return D2;
}

static function double BS_Call(double S, double K, double Vol, double R, double Q, double T) 
{
  double result;
  double BS_Call;
  BS_Call = (((S * CommonLib.Math.Pow(2.718281828, (-1 * Q * T))) * 
            Norm_S_Dist(D1(S, K, Vol, R, Q, T), true)) - ((K * CommonLib.Math.Pow(2.718281828, (-1 * R * T))) * Norm_S_Dist(D2(S, K, Vol, R, Q, T), true)));
  return BS_Call;
}

static function double BS_Put(double S, double K, double Vol, double R, double Q, double T) 
{
  double result;
  double BS_Put;
  BS_Put = (((K * CommonLib.Math.Pow(2.718281828, (-1 * R * T))) * Norm_S_Dist(-1 * D2(S, K, Vol, R, Q, T), true)) - ((S * CommonLib.Math.Pow(2.718281828, (-1 * Q * T))) * 
           Norm_S_Dist(-1 * D1(S, K, Vol, R, Q, T), true)));
  return BS_Put;
}

static function double Max(Collection[double] col) 
{ 
  double res = col.Get(0); 
  foreach x in col {
  	if (x > res) { res = x; } 
  }
  return res; 
}

static function double EBinCall(double N) 
{
    double S = 100; 
    double K = 40; 
    double Sigma = 0.35; 
    double R = 0.05; 
    double Q = 0; 
    double T = 0.75; 

    double EBinCall = 0.0;
    double Dt = 0.0;
    double U = 0.0;
    double D = 0.0;
    double Pu = 0.0;
    double Pd = 0.0;
    double U2 = 0.0;
    double Prob = 0.0;
    double CallV = 0.0;
    double I = 0.0;
    Dt = T / (1.0 * N);
    U = CommonLib.Math.Pow(2.718281828, (Sigma * CommonLib.Math.Sqrt(Dt)));
    D = 1 / (1.0 * U);
    Pu = (CommonLib.Math.Pow(2.718281828, ((( R - Q )) * Dt)) - D) / (1.0 * (( U - D )));
    Pd = (1 - Pu);
    U2 = U * U;
    S = S * CommonLib.Math.Pow(D, N);
    Prob = CommonLib.Math.Pow(Pd, N);
    CallV = Prob * Domain.Excel.Max({(( S - K )),0});
    I = 1;
    while (I <= N)    {
      S = S * U2;
      Prob = Prob * (Pu / (1.0 * Pd)) * ((( N - I )) + 1) / (1.0 * I);
      CallV = (CallV + Prob * Domain.Excel.Max({(( S - K )),0}));
      I = I + 1;
    }
    EBinCall = (CommonLib.Math.Pow(2.718281828, (-1 * R * T))) * CallV;
    return EBinCall; 
}

static function string padLeftWithInto(
	string s,
	string c,
	int n
)
{
  string result = "";

  result = pad(n - s.Length, c) + s;
  return result;
}

static function string rightAlignInto(
	string s,
	int n
)
{ 
  string result = "";

  if (n <= s.Length)
  { result = s.Substring(0, n); }
  else
  { result = pad(n - s.Length, " ") + s; }
  return result;
}

static function string capitalise(
	string str
)
{ 
  if (str.Length > 0)
  { string s1 = str.CharAt(0) + "";
    return s1.ToUpper() + str.Substring(1, str.Length - 1);
  }
  return str; 
}

static function string swapCase(
	string s
)
{
  int ind = 1;
  string res = "";

  while (ind <= s.Length)
  { string chr = "" + s.CharAt(ind - 1);
    if (chr.Equals(chr.ToUpper()))
    { res = res + chr.ToLower(); }
    else
    { res = res + chr.ToUpper(); }
    ind = ind + 1;
  }

  return res;
}

static function string padRightWithInto(
	string s,
	string c,
	int n
)
{
  string result = "";
  result = s + pad(n - s.Length, c);
  return result;
}

static function string leftAlignInto(
	string s,
	int n
)
{
  string result = "";

  if (n <= s.Length)
  { result = s.Substring(0, n); }
  else 
  { result = s + pad(n - s.Length, " "); }
  return result;
}

static function string pad(
	int n,
	string c
)
{
  string res = ""; 
  for (int i = 0; i < n; i+1)
  { res = res + c; }
  return res;
}

static function string nCopies(
	string s,
	int n
)
{
  string result = "";
  for (int i = 0; i < n; i+1)
  {
    result = result + s;
  }

  return result;
}

static function string sumStringsWithSeparator(
	Collection[string] lst,
	string sep
)
{
  string res = "";
  for (int i = 0; i < lst.Length; i+1)
  { string xx = lst.Get(i);
    res = res + xx;
    if (i < lst.Length - 1)
    { res = res + sep; }
  }
  return res;
}

static function string leftTrimWith(string str, string ch)
{
  if (str == null || str.Length == 0) 
  { return str; }
  
  for (int i = 0; i < str.Length; i+1)  
  { if (ch.Equals("" + str.CharAt(i)))
    { } 
    else 
    { string trm = str.Substring(i); 
      return trm;
    }
  }
  return ""; 
}

static function string newString(Object s)
{
   return "" + s; 
}
